schema = {
    "type": "object",
    "properties": {
        "name": {"type": "string"},
        "price": {"type": "number"},
        "in_stock": {"type": "boolean"}
    },
    "required": ["name", "price"]
}

message = client.messages.create(
    model="claude-sonnet-4-6",
    max_tokens=2048,
    output_format=schema,  # Pass schema via output_format
    messages=[{"role": "user", "content": "Return product info"}]
)

# Response is pure JSON:
# {"name": "Laptop", "price": 999.99, "in_stock": true}

message = client.messages.create(
    model="claude-sonnet-4-6",
    max_tokens=2048,
    tools=[{
        "name": "order_info",
        "description": "Return structured order data",
        "input_schema": {
            "type": "object",
            "properties": {
                "order_id": {"type": "string"},
                "customer": {"type": "string"}
            },
            "required": ["order_id", "customer"]
        },
        "strict": True  # Enable strict mode
    }],
    tool_choice={"type": "tool", "name": "order_info"},  # Force tool invocation
    messages=[{"role": "user", "content": "Get order #123"}]
)

# Response is tool call:
# {"name": "order_info", "arguments": {"order_id": "123", "customer": "John"}}
